import React, { useState, useEffect, useRef } from 'react';
import { db } from '../../utils/firebase'; 
import { doc, getDoc, updateDoc, arrayUnion } from 'firebase/firestore';
import { Camera, RefreshCw, AlertTriangle, CheckCircle2 } from 'lucide-react';

export default function MaterialWorker() {
  const [parentId, setParentId] = useState('platform no 1'); 
  const [quantity, setQuantity] = useState(1);
  const [isProcessing, setIsProcessing] = useState(false);
  const [errorAlert, setErrorAlert] = useState(null);
  const [successAlert, setSuccessAlert] = useState(null);
  
  const videoRef = useRef(null);
  const streamRef = useRef(null);
  const [cameraActive, setCameraActive] = useState(false);
  const [previewUrl, setPreviewUrl] = useState(null);

  const startCamera = async () => {
    setErrorAlert(null);
    try {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment', width: 640, height: 480 }
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        const playPromise = videoRef.current.play();
        if (playPromise !== undefined) {
          playPromise
            .then(() => setCameraActive(true))
            .catch((err) => {
              if (err.name !== 'AbortError') setErrorAlert(`Camera display failed: ${err.message}`);
            });
        }
      }
    } catch (err) {
      setErrorAlert("Webcam access nahi mila. Permissions check karein.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    if (videoRef.current) videoRef.current.srcObject = null;
    setCameraActive(false);
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  const captureFrame = () => {
    if (!videoRef.current || !cameraActive) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth || 640;
    canvas.height = videoRef.current.videoHeight || 480;
    const ctx = canvas.getContext('2d');
    ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
    
    try {
      const url = canvas.toDataURL('image/jpeg', 0.85);
      setPreviewUrl(url);
      stopCamera(); 
    } catch (err) {
      setErrorAlert("Image frame capture fail ho gaya.");
    }
  };

  const handleProcessMatrixAudit = async (e) => {
    e.preventDefault();
    setIsProcessing(true);
    setErrorAlert(null);
    setSuccessAlert(null);

    if (!parentId || parentId.trim() === "") {
      setErrorAlert("Registry identifier khaali nahi ho sakta.");
      setIsProcessing(false);
      return;
    }

    try {
      const cleanRegistryKey = parentId.trim();
      const registryDocRef = doc(db, "registry", cleanRegistryKey);
      const registrySnap = await getDoc(registryDocRef);

      if (!registrySnap.exists()) {
        // Idhar se alert() poora hata diya taaki UI ganda na ho
        setErrorAlert(`Firestore ke "registry" collection mein "${cleanRegistryKey}" naam ka document nahi mila.`);
        setIsProcessing(false);
        return;
      }

      await updateDoc(registryDocRef, {
        auditLogs: arrayUnion({
          quantity: Number(quantity),
          verificationPhoto: previewUrl || "https://via.placeholder.com/640",
          timestamp: new Date().toISOString(),
          status: "Verified"
        })
      });

      setSuccessAlert("Matrix database successfully update ho gaya.");
    } catch (error) {
      setErrorAlert(`Database Write Error: ${error.message}`);
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div style={{ backgroundColor: '#0F172A', minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }} className="w-full text-slate-100 p-6 font-sans">
      <div style={{ backgroundColor: '#1E293B', borderRadius: '12px', border: '1px solid #334155' }} className="w-full max-w-md shadow-2xl p-6">
        
        <div className="mb-6 text-center">
          <h2 className="text-xl font-bold text-white tracking-tight">Material Worker Node</h2>
          <p className="text-xs text-slate-400 mt-1">GRWMS Matrix Inventory Audit Subsystem</p>
        </div>

        {errorAlert && (
          <div style={{ backgroundColor: 'rgba(127, 29, 29, 0.4)', border: '1px solid #991b1b' }} className="mb-4 p-3 text-red-200 rounded-lg flex items-start gap-2 text-xs">
            <AlertTriangle className="w-4 h-4 text-red-400 shrink-0 mt-0.5" />
            <span>{errorAlert}</span>
          </div>
        )}

        {successAlert && (
          <div style={{ backgroundColor: 'rgba(6, 78, 59, 0.4)', border: '1px solid #065f46' }} className="mb-4 p-3 text-emerald-200 rounded-lg flex items-start gap-2 text-xs">
            <CheckCircle2 className="w-4 h-4 text-emerald-400 shrink-0 mt-0.5" />
            <span>{successAlert}</span>
          </div>
        )}

        <form onSubmit={handleProcessMatrixAudit} className="space-y-5">
          <div>
            <label className="block text-[11px] font-semibold uppercase tracking-wider text-slate-400 mb-1.5">
              Active Parent Station Registry Key
            </label>
            <input 
              type="text"
              value={parentId}
              onChange={(e) => setParentId(e.target.value)}
              style={{ backgroundColor: '#0F172A', border: '1px solid #334155', color: '#F1F5F9' }}
              className="w-full px-3 py-2 rounded-lg text-sm focus:outline-none focus:border-blue-500"
              placeholder="e.g. platform no 1"
            />
          </div>

          <div>
            <label className="block text-[11px] font-semibold uppercase tracking-wider text-slate-400 mb-1.5">
              Material Quantity / Unit Shift Weight
            </label>
            <input 
              type="number"
              min="1"
              value={quantity}
              onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
              style={{ backgroundColor: '#0F172A', border: '1px solid #334155', color: '#F1F5F9' }}
              className="w-full px-3 py-2 rounded-lg text-sm focus:outline-none focus:border-blue-500"
            />
          </div>

          <div>
            <label className="block text-[11px] font-semibold uppercase tracking-wider text-slate-400 mb-1.5">
              State Audit Photo Block Verification
            </label>
            
            <div style={{ backgroundColor: '#0F172A', border: '1px solid #334155' }} className="relative w-full aspect-video rounded-lg overflow-hidden flex items-center justify-center">
              {previewUrl ? (
                <img src={previewUrl} alt="Audit verification" className="w-full h-full object-cover" />
              ) : (
                <video ref={videoRef} className={`w-full h-full object-cover ${!cameraActive ? 'hidden' : 'block'}`} playsInline muted />
              )}

              {!cameraActive && !previewUrl && (
                <div className="text-center p-4">
                  <Camera className="w-8 h-8 text-slate-600 mx-auto mb-2 animate-pulse" />
                  <p className="text-xs text-slate-500">Camera start ho raha hai...</p>
                </div>
              )}
            </div>

            <div className="mt-2.5">
              {previewUrl ? (
                <button type="button" onClick={() => { setPreviewUrl(null); startCamera(); }} className="w-full py-1.5 px-3 bg-slate-800 hover:bg-slate-700 text-slate-200 border border-slate-600 text-xs font-medium rounded-md flex items-center justify-center gap-1.5">
                  <RefreshCw className="w-3.5 h-3.5" /> Retake Picture
                </button>
              ) : (
                <button type="button" onClick={captureFrame} disabled={!cameraActive} className="w-full py-1.5 px-3 bg-blue-600 hover:bg-blue-500 disabled:bg-slate-800 disabled:text-slate-600 text-white text-xs font-medium rounded-md flex items-center justify-center gap-1.5">
                  <Camera className="w-3.5 h-3.5" /> Capture Verification Frame
                </button>
              )}
            </div>
          </div>

          <button
            type="submit"
            disabled={isProcessing}
            className="w-full mt-2 py-2.5 px-4 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white text-xs font-semibold uppercase tracking-wider rounded-lg shadow-md disabled:opacity-50 flex items-center justify-center gap-2"
          >
            {isProcessing ? "Processing Matrix Audit Changes..." : "Commit Ingestion Sequence"}
          </button>
        </form>
      </div>
    </div>
  );
}
